import requests
import json
import os

KONG_ADMIN_URL = os.getenv('KONG_ADMIN_URL', 'http://localhost:8001')
KONG_API_KEY = os.getenv('KONG_API_KEY')

def create_service(name, url):
    headers = {
        'Content-Type': 'application/json',
        'Kong-Admin-Token': KONG_API_KEY
    }
    data = {
        'name': name,
        'url': url
    }
    response = requests.post(f'{KONG_ADMIN_URL}/services', headers=headers, data=json.dumps(data))
    response.raise_for_status()
    return response.json()

def create_route(service_name, paths):
    headers = {
        'Content-Type': 'application/json',
        'Kong-Admin-Token': KONG_API_KEY
    }
    data = {
        'service': {'name': service_name},
        'paths': paths
    }
    response = requests.post(f'{KONG_ADMIN_URL}/routes', headers=headers, data=json.dumps(data))
    response.raise_for_status()
    return response.json()

def add_upstream_target(upstream_name, target, weight=100):
    headers = {
        'Content-Type': 'application/json',
        'Kong-Admin-Token': KONG_API_KEY
    }
    data = {
        'target': target,
        'weight': weight
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams/{upstream_name}/targets', headers=headers, data=json.dumps(data))
    response.raise_for_status()
    return response.json()

def main():
    try:
        service = create_service('example-service', 'http://example.com')
        print(f'Service created: {service}')

        route = create_route('example-service', ['/example'])
        print(f'Route created: {route}')

        upstream_target = add_upstream_target('example-upstream', 'example.com:80')
        print(f'Upstream target added: {upstream_target}')

    except requests.exceptions.RequestException as e:
        print(f'Error: {e}')

if __name__ == '__main__':
    main()